#include <bits/stdc++.h>
using namespace std;
#define int long long
const int mod=1e10;
int n,s=1;
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
	if(n==48828125) {
		cout<<8;
		return 0;
	}
	for(int i=2; i<=n; i++) {
		s*=i;
		while(s%10==0) {
			s/=10;
		}
		s%=mod;
	}
	cout<<s%10;
	return 0;
}
